select.if:
select parentPos.code as parentCode, curPos.id, curPos.code, curPos.name, curPos.valid, curPos.modify_time as modifyTime, curPos.description, curPos.full_path as fullPath, curPos.lay_no as layNo, curPos.sort, dept.code as deptCode, dept.name as deptName, company.code as companyCode, company.full_name as companyFullName, company.short_name as companyShortName from org_position curPos left join org_position parentPos on curPos.parent_id = parentPos.id left join org_department dept on curPos.dep_id = dept.id left join org_company company on curPos.company_id = company.id
where curPos.modify_time > #{modifyTime}
where curPos.valid = 1
order by curPos.lay_no, curPos.sort
limit #{pageSize} offset #{offset}

select count(*) from org_position curPos left join org_position parentPos on curPos.parent_id = parentPos.id left join org_department dept on curPos.dep_id = dept.id left join org_company company on curPos.company_id = company.id
where curPos.modify_time > #{modifyTime}
where curPos.valid = 1
